To test the `zip_dicts` function thoroughly, we'll write pytest-style tests covering happy path workflows, edge cases, and error conditions. The tests validate that the function correctly merges keys from input dictionaries, preserves input order of values, and raises appropriate errors for invalid inputs.

```python
import pytest
from your_module import zip_dicts  # Import the function from its source file

# ------------------------------
# Happy Path Tests (valid inputs, common usage)
# ------------------------------
def test_zip_two_dicts_with_overlapping_and_unique_keys():
    """Test core functionality with 2 dictionaries that share some keys."""
    d1 = {"a": 1, "b": 2}
    d2 = {"b": 3, "c": 4}
    result = zip_dicts(d1, d2)
    expected = {
        "a": [1, None],
        "b": [2, 3],
        "c": [None, 4]
    }
    assert result == expected

def test_zip_three_or_more_dicts():
    """Test the function works with any number of input dictionaries."""
    d1 = {"x": 10, "y": 20}
    d2 = {"y": 30, "z": 40}
    d3 = {"x": 50, "z": 60}
    result = zip_dicts(d1, d2, d3)
    expected = {
        "x": [10, None, 50],
        "y": [20, 30, None],
        "z": [None, 40, 60]
    }
    assert result == expected

# ------------------------------
# Edge Case Tests (rare/extreme valid inputs)
# ------------------------------
def test_zip_no_input_dicts():
    """Test calling the function with no arguments returns empty dict."""
    assert zip_dicts() == {}

def test_zip_single_input_dict():
    """Test function works with only one input dictionary."""
    d = {"foo": "bar", "num": 42}
    result = zip_dicts(d)
    assert result == {"foo": ["bar"], "num": [42]}

def test_zip_all_empty_dicts():
    """Test merging multiple empty dictionaries returns empty output."""
    assert zip_dicts({}, {}, {}) == {}

def test_zip_all_shared_keys():
    """Test all input dictionaries have identical sets of keys."""
    d1 = {"a": 1, "b": 2}
    d2 = {"a": 3, "b": 4}
    d3 = {"a": 5, "b": 6}
    result = zip_dicts(d1, d2, d3)
    assert result == {"a": [1, 3, 5], "b": [2, 4, 6]}

def test_none_as_valid_value():
    """Test `None` as an intentional value is handled correctly (matches function's get() behavior)."""
    d1 = {"a": None, "b": 2}
    d2 = {"c": None}
    result = zip_dicts(d1, d2)
    expected = {
        "a": [None, None],
        "b": [2, None],
        "c": [None, None]
    }
    assert result == expected

def test_non_string_hashable_keys():
    """Test function works with non-string valid dictionary keys (integers, tuples)."""
    d1 = {1: "int_key", (2, 3): "tuple_key"}
    d2 = {1: "another_int", "string_key": "yes"}
    result = zip_dicts(d1, d2)
    expected = {
        1: ["int_key", "another_int"],
        (2, 3): ["tuple_key", None],
        "string_key": [None, "yes"]
    }
    assert result == expected

